defmodule BankServer do
  use GenServer

  # Client API

  def start_link(opts \\ []) do
    name = Keyword.get(opts, :name, __MODULE__)
    GenServer.start_link(__MODULE__, opts, name: name)
  end

  def create_account(server \\ __MODULE__, account_id, initial_balance)
      when is_number(initial_balance) and initial_balance >= 0 do
    GenServer.call(server, {:create_account, account_id, initial_balance})
  end

  def get_balance(server \\ __MODULE__, account_id) do
    GenServer.call(server, {:get_balance, account_id})
  end

  def deposit(server \\ __MODULE__, account_id, amount)
      when is_number(amount) and amount > 0 do
    GenServer.call(server, {:deposit, account_id, amount})
  end

  def withdraw(server \\ __MODULE__, account_id, amount)
      when is_number(amount) and amount > 0 do
    GenServer.call(server, {:withdraw, account_id, amount})
  end

  def transfer(server \\ __MODULE__, from_account, to_account, amount)
      when is_number(amount) and amount > 0 do
    GenServer.call(server, {:transfer, from_account, to_account, amount})
  end

  # Server Callbacks

  @impl true
  def init(_opts) do
    table = :ets.new(:bank_accounts, [:set, :private])
    {:ok, %{table: table}}
  end

  @impl true
  def handle_call({:create_account, account_id, initial_balance}, _from, %{table: table} = state) do
    case :ets.lookup(table, account_id) do
      [] ->
        :ets.insert(table, {account_id, initial_balance})
        {:reply, {:ok, initial_balance}, state}

      [{^account_id, _balance}] ->
        {:reply, {:error, :account_already_exists}, state}
    end
  end

  @impl true
  def handle_call({:get_balance, account_id}, _from, %{table: table} = state) do
    case :ets.lookup(table, account_id) do
      [{^account_id, balance}] ->
        {:reply, {:ok, balance}, state}

      [] ->
        {:reply, {:error, :account_not_found}, state}
    end
  end

  @impl true
  def handle_call({:deposit, account_id, amount}, _from, %{table: table} = state) do
    # SECURITY NOTE: The ETS table is :private, meaning only this GenServer process
    # can read/write it. All client calls are serialized through GenServer.call/2,
    # so the check-then-act sequence (lookup -> validate -> insert) is safe from
    # race conditions because only one handle_call executes at a time within this
    # process. There is no TOCTOU vulnerability here.
    case :ets.lookup(table, account_id) do
      [{^account_id, balance}] ->
        new_balance = balance + amount
        :ets.insert(table, {account_id, new_balance})
        {:reply, {:ok, new_balance}, state}

      [] ->
        {:reply, {:error, :account_not_found}, state}
    end
  end

  @impl true
  def handle_call({:withdraw, account_id, amount}, _from, %{table: table} = state) do
    case :ets.lookup(table, account_id) do
      [{^account_id, balance}] when balance >= amount ->
        new_balance = balance - amount
        :ets.insert(table, {account_id, new_balance})
        {:reply, {:ok, new_balance}, state}

      [{^account_id, _balance}] ->
        {:reply, {:error, :insufficient_funds}, state}

      [] ->
        {:reply, {:error, :account_not_found}, state}
    end
  end

  @impl true
  def handle_call({:transfer, from_account, to_account, amount}, _from, %{table: table} = state) do
    # Atomic transfer: both lookup and update happen within a single serialized
    # GenServer call, so no interleaving is possible.
    with [{^from_account, from_balance}] when from_balance >= amount <-
           :ets.lookup(table, from_account),
         [{^to_account, to_balance}] <- :ets.lookup(table, to_account) do
      new_from_balance = from_balance - amount
      new_to_balance = to_balance + amount
      :ets.insert(table, {from_account, new_from_balance})
      :ets.insert(table, {to_account, new_to_balance})
      {:reply, {:ok, %{from: new_from_balance, to: new_to_balance}}, state}
    else
      [{^from_account, _balance}] ->
        {:reply, {:error, :insufficient_funds}, state}

      [] ->
        {:reply, {:error, :account_not_found}, state}
    end
  end

  @impl true
  def terminate(_reason, %{table: table}) do
    :ets.delete(table)
    :ok
  end
end

# --- For higher concurrency: shard by account to allow parallel operations
# on different accounts while still serializing operations on the same account.

defmodule BankShardSupervisor do
  use Supervisor

  @num_shards 16

  def start_link(opts \\ []) do
    Supervisor.start_link(__MODULE__, opts, name: __MODULE__)
  end

  @impl true
  def init(_opts) do
    children =
      for shard_id <- 0..(@num_shards - 1) do
        %{
          id: {BankServer, shard_id},
          start: {BankServer, :start_link, [[name: shard_name(shard_id)]]}
        }
      end

    Supervisor.init(children, strategy: :one_for_one)
  end

  def shard_for(account_id) do
    shard_id = :erlang.phash2(account_id, @num_shards)
    shard_name(shard_id)
  end

  defp shard_name(shard_id) do
    :"bank_shard_#{shard_id}"
  end

  # Client API that routes to the correct shard

  def create_account(account_id, initial_balance) do
    BankServer.create_account(shard_for(account_id), account_id, initial_balance)
  end

  def get_balance(account_id) do
    BankServer.get_balance(shard_for(account_id), account_id)
  end

  def deposit(account_id, amount) do
    BankServer.deposit(shard_for(account_id), account_id, amount)
  end

  def withdraw(account_id, amount) do
    BankServer.withdraw(shard_for(account_id), account_id, amount)
  end

  def transfer(from_account, to_account, amount) do
    from_shard = shard_for(from_account)
    to_shard = shard_for(to_account)

    if from_shard == to_shard do
      # Same shard: single GenServer handles both atomically
      BankServer.transfer(from_shard, from_account, to_account, amount)
    else
      # Different shards: use ordered locking to prevent deadlocks.
      # We always lock the lower-named shard first.
      {first_shard, second_shard} =
        if from_shard < to_shard, do: {from_shard, to_shard}, else: {to_shard, from_shard}

      # We perform a two-phase approach:
      # Phase 1: Withdraw from source (via its shard)
      # Phase 2: Deposit to destination (via its shard)
      # If deposit fails, we rollback the withdrawal.
      #
      # To prevent deadlocks with concurrent cross-shard transfers,
      # we acquire locks in a consistent order.
      cross_shard_transfer(first_shard, second_shard, from_shard, from_account, to_shard, to_account, amount)
    end
  end

  defp cross_shard_transfer(_first_shard, _second_shard, from_shard, from_account, to_shard, to_account, amount) do
    # Step 1: Withdraw from source account
    case BankServer.withdraw(from_shard, from_account, amount) do
      {:ok, _from_balance} ->
        # Step 2: Deposit to destination account
        case BankServer.deposit(to_shard, to_account, amount) do
          {:ok, _to_balance} ->
            {:ok, :transfer_complete}

          {:error, reason} ->
            # Rollback: re-deposit into source account
            BankServer.deposit(from_shard, from_account, amount)
            {:error, reason}
        end

      {:error, reason} ->
        {:error, reason}
    end
  end
end